local SessionManager = {}
SessionManager.__index = SessionManager

function SessionManager.new(config)
    local self = setmetatable({}, SessionManager)
    self.token_length = (config and config.token_length) or 64
    self.nonce_length = (config and config.nonce_length) or 32
    self.token_ttl = (config and config.token_ttl) or 3600
    self.sessions = {}
    return self
end

local function generate_random_hex(length)
    local chars = "0123456789abcdef"
    local result = {}
    for i = 1, length do
        local idx = math.random(1, #chars)
        result[i] = string.sub(chars, idx, idx)
    end
    return table.concat(result)
end

local function generate_random_base62(length)
    local chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    local result = {}
    for i = 1, length do
        local idx = math.random(1, #chars)
        result[i] = string.sub(chars, idx, idx)
    end
    return table.concat(result)
end

function SessionManager:generate_token()
    local timestamp = os.time()
    local random_part = generate_random_base62(self.token_length)
    local entropy = math.random(100000, 999999)
    local token = string.format("%s_%d_%d", random_part, timestamp, entropy)
    return token
end

function SessionManager:generate_nonce()
    local nonce = generate_random_hex(self.nonce_length)
    return nonce
end

function SessionManager:generate_csrf_token()
    local part1 = generate_random_base62(16)
    local part2 = generate_random_hex(16)
    local timestamp = os.time()
    return string.format("%s.%s.%d", part1, part2, timestamp)
end

function SessionManager:create_session(user_id, metadata)
    local session_token = self:generate_token()
    local nonce = self:generate_nonce()
    local csrf_token = self:generate_csrf_token()
    local created_at = os.time()
    local expires_at = created_at + self.token_ttl

    local session = {
        session_token = session_token,
        nonce = nonce,
        csrf_token = csrf_token,
        user_id = user_id,
        created_at = created_at,
        expires_at = expires_at,
        metadata = metadata or {},
        is_active = true
    }

    self.sessions[session_token] = session
    return session
end

function SessionManager:validate_session(session_token)
    local session = self.sessions[session_token]
    if not session then
        return false, "Session not found"
    end

    if not session.is_active then
        return false, "Session is inactive"
    end

    local current_time = os.time()
    if current_time > session.expires_at then
        session.is_active = false
        return false, "Session has expired"
    end

    return true, session
end

function SessionManager:refresh_session(session_token)
    local is_valid, result = self:validate_session(session_token)
    if not is_valid then
        return nil, result
    end

    local old_session = result
    old_session.is_active = false

    local new_session = self:create_session(old_session.user_id, old_session.metadata)
    self.sessions[session_token] = nil

    return new_session
end

function SessionManager:invalidate_session(session_token)
    local session = self.sessions[session_token]
    if session then
        session.is_active = false
        self.sessions[session_token] = nil
        return true, "Session invalidated"
    end
    return false, "Session not found"
end

function SessionManager:invalidate_user_sessions(user_id)
    local count = 0
    for token, session in pairs(self.sessions) do
        if session.user_id == user_id then
            session.is_active = false
            self.sessions[token] = nil
            count = count + 1
        end
    end
    return count
end

function SessionManager:cleanup_expired()
    local current_time = os.time()
    local count = 0
    for token, session in pairs(self.sessions) do
        if current_time > session.expires_at then
            self.sessions[token] = nil
            count = count + 1
        end
    end
    return count
end

function SessionManager:get_active_session_count()
    local count = 0
    local current_time = os.time()
    for _, session in pairs(self.sessions) do
        if session.is_active and current_time <= session.expires_at then
            count = count + 1
        end
    end
    return count
end

local function set_session_cookie(session_token, ttl)
    local cookie = string.format(
        "session_id=%s; Path=/; HttpOnly; Secure; SameSite=Strict; Max-Age=%d",
        session_token,
        ttl
    )
    ngx.header["Set-Cookie"] = cookie
end

local function get_session_from_cookie()
    local cookie = ngx.var.http_cookie
    if not cookie then
        return nil
    end
    local session_token = string.match(cookie, "session_id=([^;]+)")
    return session_token
end

